function Icon({ name, weight = 'regular', size = 24, ...rest }) {
  const body = (PATHS[weight] && PATHS[weight][name]) || PATHS.regular[name];
  if (!body) return null;
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 256 256"
      fill="currentColor"
      width={size}
      height={size}
      aria-hidden
      {...rest}
      dangerouslySetInnerHTML={{ __html: body }}
    />
  );
}

window.Icon = Icon;
window.ICON_NAMES = Object.keys(PATHS.regular);

// Back-compat shims for previous I.* call sites
const _aliasOf = (name) => (p) => <Icon name={name} weight={p && p.filled ? 'fill' : 'regular'} {...(p || {})} />;
window.I = {
  Home:    _aliasOf('house'),
  Search:  _aliasOf('magnifying-glass'),
  Cart:    _aliasOf('shopping-cart'),
  User:    _aliasOf('user'),
  Grid:    _aliasOf('list'),         // closest match in pulled set
  Pin:     _aliasOf('map-pin'),
  Chevron: _aliasOf('caret-right'),
  Down:    _aliasOf('caret-down'),
  Bolt:    (p) => <Icon name="lightning" weight="fill" {...(p || {})} />,
  Back:    _aliasOf('arrow-left'),
  X:       _aliasOf('x'),
  Plus:    _aliasOf('plus'),
  Minus:   _aliasOf('minus'),
  Check:   _aliasOf('check'),
};

const { useState } = React;
window.useZState = (initial) => {
  const [s, setS] = useState(initial);
  return [s, setS];
};
